def get_concordance(rule_id: str) -> list[str]:
    return CONCORDANCE_MAP.get(rule_id, [])


def get_divergence(rule_id: str) -> list[str]:
    return DIVERGENCE_MAP.get(rule_id, [])


def mechanical_confidence(rule_id: str, has_verse_ref: bool = True) -> float:
    """Compute confidence per PHASE1B_RULE_CONTRACT formula.

    Divergence counts unique SOURCE TEXTS, not individual rules.
    Multiple divergent rules from the same source = 1 divergence.
    """
    conc = len(get_concordance(rule_id))
    div_entries = get_divergence(rule_id)
    # Count unique sources, not individual rule refs
    div_sources = {entry.split(":")[0] for entry in div_entries} if div_entries else set()
    div = len(div_sources)
    verse_bonus = 0.05 if has_verse_ref else 0.0
    return min(1.0, max(0.10, 0.60 + 0.08 * conc + verse_bonus - 0.05 * div))
